import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { authService, loadService } from "../services";
import Sidebar from "../components/Sidebar";
import { getUserMenuItems } from "../config/menuConfig";
import { FiBox, FiMail, FiUser } from "react-icons/fi";
import "../styles/Dashboard.css";

const StatCard = ({ icon: Icon, title, value, color }) => (
  <div className="stat-panel">
    <div className="stat-icon" style={{ backgroundColor: `${color}20` }}>
      <Icon size={28} style={{ color }} />
    </div>
    <div className="stat-info">
      <p className="stat-title">{title}</p>
      <h3 className="stat-value">{value}</h3>
    </div>
  </div>
);

const UserDashboard = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loads, setLoads] = useState([]);
  const [loadingLoads, setLoadingLoads] = useState(true);

  const fetchUserLoads = async () => {
    try {
      setLoadingLoads(true);
      const response = await loadService.getLoads();
      // Filter loads created by current user
      const userLoads = (response.loads || []).filter(
        (load) => load.createdBy === user?.id
      );
      setLoads(userLoads);
    } catch (error) {
      console.error("Error fetching loads:", error);
    } finally {
      setLoadingLoads(false);
    }
  };

  useEffect(() => {
    fetchUserLoads();
  }, []);

  const handleLogout = () => {
    authService.logout();
    navigate("/user/login");
  };

  const menuItems = getUserMenuItems(navigate);

  const isActive = (path) => location.pathname === path;

  return (
    <div className="dashboard-container">
      <Sidebar
        sidebarOpen={sidebarOpen}
        setSidebarOpen={setSidebarOpen}
        menuItems={menuItems}
        isActive={isActive}
        handleLogout={handleLogout}
        sidebarTitle="📦 Loads"
      />

      {/* Main Content */}
      <main className="dashboard-main">
        <div className="dashboard-header user-header">
          <div className="header-top">
            <h1>User Dashboard</h1>
            <p className="subtitle">Welcome, {user?.name}!</p>
          </div>
          <div className="header-actions">
            <button
              onClick={() => navigate("/create-load")}
              className="btn-primary"
            >
              Create New Load
            </button>
          </div>
        </div>

        <div className="dashboard-content">
          <div className="info-card user-info">
            <h3>Load Management System</h3>
            <p>Manage your loads efficiently with our platform.</p>
            <ul>
              <li>Create and manage loads</li>
              <li>Track load status</li>
              <li>View all available loads</li>
              <li>Edit or delete your loads</li>
            </ul>
            <button onClick={() => navigate("/loads")} className="btn-primary">
              Go to Loads
            </button>
          </div>

          <div className="quick-stats">
            <div className="stat-card">
              <h4>Email</h4>
              <p>{user?.email}</p>
            </div>
            <div className="stat-card">
              <h4>Role</h4>
              <p className="role-badge user-badge">
                {user?.role?.toUpperCase()}
              </p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default UserDashboard;
